-- Keycloak initialization script\n-- This script runs on MySQL startup to prepare the database\n\n-- Create keycloak database if it doesn't exist\nCREATE DATABASE IF NOT EXISTS keycloak CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;\n\n-- Use keycloak database\nUSE keycloak;\n\n-- Note: Keycloak will auto-create tables on first startup\n-- This script is here for reference and future customizations\n\n-- Optional: Create indexes for performance\nCREATE INDEX IF NOT EXISTS idx_user_email ON user_entity(email);\nCREATE INDEX IF NOT EXISTS idx_user_username ON user_entity(username);\nCREATE INDEX IF NOT EXISTS idx_federated_user ON federated_user(user_id);\nCREATE INDEX IF NOT EXISTS idx_federated_link ON federated_link(user_id);\n
